import React, { useState } from 'react';
import { FaUserGraduate } from 'react-icons/fa';
import { FiDownload } from 'react-icons/fi';

function App() {
    const [name, setName] = useState('');

    const handleGenerate = async (e) => {
        e.preventDefault();
        if (!name.trim()) {
            alert('Please enter your name');
            return;
        }

        const response = await fetch('http://localhost:5000/generate-certificate', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ name })
        });

        const blob = await response.blob();
        const url = window.URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `${name}-certificate.pdf`;
        document.body.appendChild(a);
        a.click();
        a.remove();
    };

    return (
        <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-indigo-100 to-blue-200 px-4 py-10">
            <div className="bg-white shadow-2xl rounded-3xl p-10 w-full max-w-lg border border-indigo-100">
                <div className="text-center mb-6">
                    <FaUserGraduate className="text-4xl text-indigo-600 mx-auto mb-2" />
                    <h1 className="text-3xl font-extrabold text-indigo-800">Certificate Generator</h1>
                    <p className="text-gray-600 mt-2">Enter your full name below to get your custom certificate.</p>
                </div>
                <form onSubmit={handleGenerate} className="space-y-5">
                    <div className="text-left">
                        <label className="block text-sm font-medium text-gray-700 mb-1">Your Name</label>
                        <input
                            type="text"
                            placeholder="e.g. John Doe"
                            value={name}
                            onChange={(e) => setName(e.target.value)}
                            className="w-full px-4 py-3 border border-gray-300 rounded-xl shadow-sm focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition"
                        />
                    </div>
                    <button
                        type="submit"
                        className="flex items-center justify-center gap-2 w-full bg-indigo-600 text-white py-3 rounded-xl font-semibold hover:bg-indigo-700 transition duration-200"
                    >
                        <FiDownload className="text-lg" />
                        Generate Certificate
                    </button>
                </form>
            </div>
        </div>
    );
}

export default App;
